blocks.body:
{
    "level":  "B1",
    "intro":  "W tym temacie zobaczysz, jak tworzy i stosowa \u003cstrong\u003ePast Perfect Passive\u003c/strong\u003e oraz czym ta forma rni si od innych czasw przeszych.",
    "rules":  [
                  {
                      "label":  "Wzr",
                      "color":  "emerald",
                      "text":  "\u003cstrong\u003esubject + had been + V3\u003c/strong\u003e:",
                      "example":  "The work had been completed before the deadline."
                  },
                  {
                      "label":  "Przeczenie",
                      "color":  "rose",
                      "text":  "\u003cstrong\u003esubject + had not been + V3\u003c/strong\u003e:",
                      "example":  "The letter had not been sent before he left."
                  },
                  {
                      "label":  "Pytanie",
                      "color":  "blue",
                      "text":  "\u003cstrong\u003eHad + subject + been + V3?\u003c/strong\u003e",
                      "example":  "Had the project been finished before the meeting?"
                  }
              ]
}

{
    "title":  "1. Struktura strony biernej Past Perfect",
    "intro":  "\u003cstrong\u003eHad\u003c/strong\u003e ma t sam form dla wszystkich osb, a \u003cstrong\u003ebeen\u003c/strong\u003e pozostaje staym elementem konstrukcji.",
    "items":  [
                  {
                      "label":  "Wszystkie osoby",
                      "title":  "had been + V3",
                      "subtitle":  "I / You / He / She / It / We / They had been invited."
                  },
                  {
                      "label":  "Liczba pojedyncza",
                      "title":  "had been + V3",
                      "subtitle":  "The report had been submitted."
                  },
                  {
                      "label":  "Liczba mnoga",
                      "title":  "had been + V3",
                      "subtitle":  "All the tasks had been completed."
                  },
                  {
                      "label":  "Uwaga",
                      "title":  "been jest stae",
                      "subtitle":  "Po had zawsze stoi been, a dopiero potem V3."
                  }
              ]
}

{
    "title": "2. Zdania twierdzące",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "Kolejność słów: <strong>podmiot + był + był + V3 (+ według agenta)</strong>",
            "examples": [
                {
                    "en": "The project had been completed before the deadline.",
                    "ua": "Projekt został ukończony przed terminem."
                },
                {
                    "en": "All the tickets had been sold before we arrived.",
                    "ua": "Wszystkie bilety zostały wyprzedane przed naszym przyjazdem."
                },
                {
                    "en": "The problem had been solved by the time they called.",
                    "ua": "Problem został rozwiązany zanim zadzwonili."
                },
                {
                    "en": "The documents had been signed by the manager.",
                    "ua": "Dokumenty podpisał menadżer."
                }
            ]
        },
        {
            "label": "Do innego przeszłego działania",
            "color": "sky",
            "description": "Kiedy ważne jest pokazanie, że dana czynność <strong>poprzedza inną</strong>:",
            "examples": [
                {
                    "en": "The house had been cleaned before the guests came.",
                    "ua": "Dom został posprzątany przed przyjazdem gości."
                },
                {
                    "en": "The email had been sent before he asked about it.",
                    "ua": "List został wysłany, zanim poprosił."
                },
                {
                    "en": "The decision had been made before the meeting started.",
                    "ua": "Decyzja została podjęta przed rozpoczęciem spotkania."
                }
            ]
        }
    ]
}

{
    "title": "3. Kiedy używać strony biernej Past Perfect?",
    "sections": [
        {
            "label": "Akcja do innej przeszłości",
            "color": "emerald",
            "description": "Kiedy jedna czynność <strong>zakończyła się wcześniej</strong> niż inna czynność przeszła:",
            "examples": [
                {
                    "en": "The work had been finished before the boss arrived.",
                    "ua": "Pracę zakończono przed przybeingm szefa."
                },
                {
                    "en": "The movie had been released before I heard about it.",
                    "ua": "Film pojawił się, zanim o nim usłyszałem."
                },
                {
                    "en": "The cake had been eaten before I got home.",
                    "ua": "Ciasto zostało zjedzone przed moim przyjazdem."
                }
            ]
        },
        {
            "label": "Do pewnego momentu",
            "color": "blue",
            "description": "Do <strong>określonego czasu lub wydarzenia</strong> w przeszłości:",
            "examples": [
                {
                    "en": "By 5 PM, the report had been submitted.",
                    "ua": "Zgłoszenie wpłynęło do godziny 17:00."
                },
                {
                    "en": "By the end of the day, all tasks had been completed.",
                    "ua": "Do końca dnia wszystkie zadania zostały wykonane."
                },
                {
                    "en": "By last week, the decision had been made.",
                    "ua": "Decyzja została podjęta w zeszłym tygodniu."
                }
            ]
        },
        {
            "label": "W opowieściach",
            "color": "amber",
            "description": "Aby uzyskać <strong>historię</strong> w relacjach:",
            "examples": [
                {
                    "en": "She found out that her car had been stolen.",
                    "ua": "Dowiedziała się, że skradziono jej samochód."
                },
                {
                    "en": "He discovered that the money had been hidden.",
                    "ua": "Odkrył, że pieniądze zostały ukryte."
                },
                {
                    "en": "They realized the door had been left unlocked.",
                    "ua": "Zorientowali się, że drzwi pozostały otwarte."
                }
            ]
        }
    ]
}

{
    "title":  "4. Zdania przeczące",
    "sections":  [
                     {
                         "label":  "Struktura",
                         "color":  "rose",
                         "description":  "\u003cstrong\u003eHad + subject + been + V3?\u003c/strong\u003e",
                         "examples":  [
                                          {
                                              "en":  "The report had not been submitted by the deadline.",
                                              "ua":  "Raport nie został złożony w terminie."
                                          },
                                          {
                                              "en":  "The documents had not been signed before the meeting.",
                                              "ua":  "Przed posiedzeniem dokumenty nie zostały podpisane."
                                          },
                                          {
                                              "en":  "The problem had not been solved when they arrived.",
                                              "ua":  "Po przybyciu na miejsce problem nie został rozwiązany."
                                          },
                                          {
                                              "en":  "The changes had not been approved yet.",
                                              "ua":  "Zmiany nie zostały jeszcze zatwierdzone."
                                          }
                                      ]
                     },
                     {
                         "label":  "Pytania z wh-",
                         "color":  "amber",
                         "description":  "\u003cstrong\u003eWh-word + had + subject + been + V3?\u003c/strong\u003e",
                         "examples":  [
                                          {
                                              "en":  "The email hadn\u0027t been sent before he left.",
                                              "ua":  "List nie został wysłany przed jego wyjazdem."
                                          },
                                          {
                                              "en":  "The tasks hadn\u0027t been completed on time.",
                                              "ua":  "Zadanie nie zostało wykonane w terminie."
                                          },
                                          {
                                              "en":  "The decision hadn\u0027t been made by then.",
                                              "ua":  "Żadna decyzja nie została wówczas podjęta."
                                          }
                                      ]
                     }
                 ]
}

{
    "title": "5. Zdania pytające",
    "sections": [
        {
            "label": "Pytania yes/no",
            "color": "blue",
            "description": "<strong>Had</strong> znalazł się na szczycie: <strong>Had + podmiot + był + V3?</strong>",
            "examples": [
                {
                    "en": "Had the report been finished before the meeting?",
                    "ua": "Skończyłeś raport przed spotkaniem?"
                },
                {
                    "en": "Had the documents been signed?",
                    "ua": "Podpisałeś dokumenty?"
                },
                {
                    "en": "Had the problem been solved by then?",
                    "ua": "Czy do tego czasu problem został rozwiązany?"
                },
                {
                    "en": "Had you ever been interviewed before?",
                    "ua": "Czy kiedykolwiek wcześniej udzielałeś wywiadu?"
                }
            ]
        },
        {
            "label": "Jakie pytanie",
            "color": "sky",
            "description": "<strong>Wh-word + miał + podmiot + był + V3?</strong>",
            "examples": [
                {
                    "en": "What had been done before he arrived?",
                    "ua": "Co zrobiono przed jego przybeingm?"
                },
                {
                    "en": "Why had the meeting been cancelled?",
                    "ua": "Dlaczego spotkanie zostało odwołane?"
                },
                {
                    "en": "Where had the money been hidden?",
                    "ua": "Gdzie ukryłeś pieniądze?"
                },
                {
                    "en": "How had the problem been solved?",
                    "ua": "Jak rozwiązałeś problem?"
                }
            ]
        },
        {
            "label": "Krótkie odpowiedzi",
            "color": "amber",
            "description": "Odpowiedzi zawierające <strong>Tak/Nie + zaimek + had (not)</strong>:",
            "examples": [
                {
                    "en": "Had the email been sent? — Yes, it had. / No, it hadn't.",
                    "ua": "Wysłałeś list? - Tak. / NIE."
                },
                {
                    "en": "Had they been informed? — Yes, they had. / No, they hadn't.",
                    "ua": "Czy zostali poinformowani? - Tak. / NIE."
                }
            ]
        }
    ]
}

{
    "title":  "6. Porwnanie: strona czynna i bierna w Past Perfect",
    "intro":  "Jak zamienić zdanie czynne w stronę bierną:",
    "rows":  [
                 {
                     "en":  "Active: They had completed the project.",
                     "ua":  "Ukończyli projekt.",
                     "note":  "→ Passive: The project had been completed."
                 },
                 {
                     "en":  "Active: Someone had stolen my bike.",
                     "ua":  "Ktoś ukradł mój rower.",
                     "note":  "→ Passive: My bike had been stolen."
                 },
                 {
                     "en":  "Active: The company had hired new staff.",
                     "ua":  "Firma zatrudniła nowych pracowników.",
                     "note":  "→ Passive: New staff had been hired."
                 },
                 {
                     "en":  "Active: We had made a decision.",
                     "ua":  "Podjęliśmy decyzję.",
                     "note":  "→ Passive: A decision had been made."
                 }
             ],
    "warning":  "📌 Znaczniki czasu (wcześniej, już) pozostają!"
}

{
    "title":  "7. Porównanie wszystkich form biernych czasu przeszłego",
    "intro":  "Różnica między trzema formami czasu przeszłego w stronie biernej:",
    "rows":  [
                 {
                     "en":  "Past Simple: The room was cleaned yesterday.",
                     "ua":  "Pokój był sprzątany wczoraj.",
                     "note":  "→ Fakt z przeszłości"
                 },
                 {
                     "en":  "Past Continuous: The room was being cleaned when I arrived.",
                     "ua":  "Kiedy przyjechałem, pokój był sprzątany.",
                     "note":  "→ Ciągłe działanie w chwili przeszłej"
                 },
                 {
                     "en":  "Past Perfect: The room had been cleaned before I arrived.",
                     "ua":  "Pokój został posprzątany przed moim przyjazdem.",
                     "note":  "→ Akcja do innej przeszłości"
                 }
             ],
    "warning":  " Past Perfect Passive podkrela, e jedna czynno zostaa zakoczona przed innym wydarzeniem w przeszoci."
}

{
    "title": "8. Markery czasu dla Past Perfect Passive",
    "intro": "Typowe słowa i wyrażenia, które często pojawiają się przy tej formie:",
    "items": [
        {
            "label": "Before / by the time",
            "title": "before, by the time, earlier",
            "subtitle": "The application had been received before noon."
        },
        {
            "label": "Already / yet",
            "title": "already, yet, still",
            "subtitle": "The task had already been completed."
        },
        {
            "label": "Just / recently",
            "title": "just, recently",
            "subtitle": "The email had just been sent when he arrived."
        },
        {
            "label": "Ever / never / before",
            "title": "ever, never, before",
            "subtitle": "Had this method ever been used before?"
        }
    ]
}

{
    "title": "9. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Brak been.",
            "wrong": "The report had completed before.",
            "right": "✅ The report had been completed before."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Mylenie being i been.",
            "wrong": "The work had being done.",
            "right": "✅ The work had been done."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Użycie was zamiast had.",
            "wrong": "The letter was been sent before.",
            "right": "✅ The letter had been sent before."
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Past Simple zamiast Past Perfect.",
            "wrong": "The email was sent before he arrived. (gdy ważna jest kolejność)",
            "right": "✅ The email had been sent before he arrived."
        }
    ]
}
